arguments.argument:
if global.gamePaused=false
{
  if shaking
  {
    timeUntilFall-=1
    if timeUntilFall<=0
    {
      shakeX=0
      yAcc=grav
      if yVel>4
        yVel=4
    }
    else
    {
      if shakeX=1
        shakeX=-1
      else
        shakeX=1
    }
  }
  else
  {
    //if the character stands on the platform, start the timer
    if isCollisionCharacterTop(1,0)
      shaking=1
  }
  
  if y>=room_height+64
    instance_destroy()
}
